mapper.select:
SELECT OPER_ID, TITLE, BUSINESS_TYPE, METHOD, REQUEST_METHOD, OPER_TYPE, OPER_USER_NAME, OPER_USER_ID, OPER_URL, OPER_IP, OPER_LOCATION, STATUS, ERROR_MSG, OPER_TIME, OPER_PARAM, JSON_RESULT, Cost_Time FROM SYS_OPER_LOG WHERE 1=1
AND (TITLE LIKE #{title,jdbcType=VARCHAR})
AND (METHOD LIKE #{method,jdbcType=VARCHAR})
AND OPER_USER_NAME LIKE #{operUserName,jdbcType=VARCHAR}
AND BUSINESS_TYPE = #{businessType,jdbcType=VARCHAR}
AND OPER_TYPE = #{operType,jdbcType=VARCHAR}
AND STATUS = #{status,jdbcType=VARCHAR}
AND OPER_TIME >= concat(#{beginTimes}, ' 00:00:00')
AND OPER_TIME <= concat(#{endTimes}, ' 23:59:59')
ORDER BY OPER_TIME DESC
